// RAZORPAY SLI DEFINITIONS
//
// SLI 1: PAYMENT AVAILABILITY
//   User journey: customer completes a payment without error
//   Good event: payment request returns 200 with status='success'
//   Total events: all payment requests
//   PromQL:
//     sum(rate(payments_total_total{status='success'}[30d]))
//     / sum(rate(payments_total_total[30d]))
//   SLO target: 99.9% (at most 0.1% failed payments)
//   Note: 4xx client errors (invalid card) may be excluded — they're user error

// SLI 2: PAYMENT LATENCY
//   User journey: customer sees payment confirmation within 2 seconds
//   Good event: payment completes in < 2s
//   Total events: all payment requests
//   PromQL:
//     sum(rate(payments_duration_seconds_bucket{le='2'}[30d]))
//     / sum(rate(payments_duration_seconds_count[30d]))
//   SLO target: 95% of payments in < 2 seconds
//   Note: uses histogram bucket le='2' (≤ 2 seconds)

// SLI 3: CHECKOUT AVAILABILITY
//   User journey: customer reaches the checkout page
//   Good event: GET /checkout returns 2xx or 3xx
//   Total events: all GET /checkout requests
//   PromQL:
//     sum(rate(http_server_requests_seconds_count{uri='/checkout',status=~'2..|3..'}[30d]))
//     / sum(rate(http_server_requests_seconds_count{uri='/checkout'}[30d]))
//   SLO target: 99.95%

public class SLIDefinitions {
    public static void main(String[] a) {
        System.out.println("SLI = good events / total events");
        System.out.println("Always: specific, measurable, user-centric");
    }
}

