import io.micrometer.core.instrument.*;
import org.springframework.stereotype.*;
import java.util.concurrent.atomic.AtomicLong;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.beans.factory.annotation.Autowired;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;

@Service
class ErrorBudgetTracker {
    private final MeterRegistry reg;
    private final AtomicLong totalRequests  = new AtomicLong(0);
    private final AtomicLong failedRequests = new AtomicLong(0);
    private static final double SLO_TARGET      = 0.999;    // 99.9%
    private static final double ERROR_BUDGET    = 1 - SLO_TARGET;  // 0.001
    private static final double MONTH_MINUTES   = 43200.0;

    ErrorBudgetTracker(MeterRegistry r) {
        reg=r;
        Gauge.builder("slo.budget.remaining.percent",this,t->t.budgetRemainingPercent())
             .description("Error budget remaining %").register(reg);
        Gauge.builder("slo.budget.consumed.minutes",this,t->t.budgetConsumedMinutes())
             .description("Error budget consumed in minutes").register(reg);
    }

    void recordRequest(boolean success) {
        totalRequests.incrementAndGet();
        if (!success) failedRequests.incrementAndGet();
    }

    double currentErrorRate() {
        long total = totalRequests.get();
        return total == 0 ? 0 : (double) failedRequests.get() / total;
    }

    double budgetRemainingPercent() {
        double consumed = currentErrorRate() / ERROR_BUDGET;
        return Math.max(0, (1 - consumed) * 100);
    }

    double budgetConsumedMinutes() {
        return currentErrorRate() / ERROR_BUDGET * MONTH_MINUTES;
    }

    boolean shouldFreezeDeployments() {
        return budgetRemainingPercent() < 20.0;  // < 20% remaining = freeze
    }
}

@SpringBootTest
class ErrorBudgetTest {
    @Autowired ErrorBudgetTracker tracker;
    @BeforeEach void reset(){tracker.totalRequests.set(0);tracker.failedRequests.set(0);}

    @Test void fullBudgetWithNoErrors(){
        for(int i=0;i<1000;i++) tracker.recordRequest(true);
        assertEquals(100.0, tracker.budgetRemainingPercent(), 0.01);
        assertFalse(tracker.shouldFreezeDeployments());
    }

    @Test void budgetConsumedByErrors(){
        for(int i=0;i<999;i++) tracker.recordRequest(true);
        for(int i=0;i<1;i++)   tracker.recordRequest(false);
        // error rate = 0.001 (0.1%) = EXACTLY the error budget
        // remaining = 0% (fully consumed)
        assertTrue(tracker.budgetRemainingPercent() <= 5.0);
        assertTrue(tracker.shouldFreezeDeployments());
    }
}

// SYMPTOM-BASED ALERTS (good — user is impacted):
// ✅ 2. Payment error rate > 1%
//    → User: payments failing. Clear user impact. Good alert.
//    → Action: check CB, DB, gateway status

// ✅ 4. p99 latency > 500ms
//    → User: payments slow. User is waiting. Good alert.
//    → Action: check Zipkin traces for slow span

// CAUSE-BASED ALERTS (bad — may not impact users YET):
// ❌ 1. CPU > 80%
//    → Problem: high CPU doesn't mean users are impacted.
//      JIT compilation can spike CPU without any user impact.
//    → Fix: alert on symptoms instead.
//      Only page if CPU > 80% AND error rate > 0.5%
//      Better: drop this alert entirely, let error rate catch real issues.

// ❌ 3. Thread pool queue depth > 100
//    → Problem: queue depth is a leading indicator but not a symptom.
//      Queue depth might briefly spike during traffic bursts without errors.
//    → Fix: alert on queue_depth > 100 for 5 minutes (sustained = problem)
//      Or: alert only if queue_depth > 100 AND p99 > 500ms (correlated symptoms)

// ❌ 5. DB connection pool > 90%
//    → Problem: 90% pool isn't necessarily causing errors yet.
//    → Fix: alert on DB pool > 90% for 5 minutes (ticket, not page)
//      OR alert on DB pool > 90% AND p99 > 500ms (correlated = user impact)
//      Never wake someone up at 3am for 90% pool if payments are fast.

// ❌ 6. JVM heap > 80%
//    → Problem: JVM manages heap. 80% is normal before GC runs.
//    → Fix: alert on GC pause > 500ms/s (actual impact on request latency)
//      OR heap > 90% for 30 minutes (may indicate memory leak)
//      80% alone is noise.

public class AlertEvaluation {
    public static void main(String[] a) {
        System.out.println("Symptom = user experiencing something wrong");
        System.out.println("Cause = internal state that might lead to something wrong");
        System.out.println("Alert on symptoms: error rate, p99. Not: CPU, heap, pool%.");
    }
}

import io.micrometer.core.instrument.*;
import org.springframework.scheduling.annotation.Scheduled;
import org.springframework.stereotype.*;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.beans.factory.annotation.Autowired;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;

@Service
class HeartbeatService {
    private final Counter heartbeat;

    HeartbeatService(MeterRegistry reg) {
        heartbeat = Counter.builder("service.heartbeat")
            .description("Monotonically increasing heartbeat — fires every 30s")
            .tag("service", "payment-service")
            .register(reg);
    }

    @Scheduled(fixedRate = 30_000)
    public void beat() {
        heartbeat.increment();
        // As long as the app is running, this counter increases.
        // If app crashes: counter stops increasing.
        // Prometheus: rate(service_heartbeat_total[2m]) = 0 → absent() alert fires.
    }

    public double count() { return heartbeat.count(); }

    // ALERT RULE (prometheus/rules.yml):
    // - alert: PaymentServiceHeartbeatMissing
    //   expr: absent(service_heartbeat_total{service='payment-service'})
    //   for: 3m    # wait 3 min before alarming (scrape lag)
    //   labels: { severity: critical }
    //   annotations:
    //     summary: 'Payment service is DOWN or not sending metrics'
    //     runbook_url: '...'
    //
    // WHY THIS IS THE MOST IMPORTANT ALERT:
    // All other alerts need metrics to fire.
    // If the service crashes or scraping breaks: metrics stop → no alerts!
    // Dead man switch: alerts when monitoring itself fails.
}

@SpringBootTest
class HeartbeatTest {
    @Autowired HeartbeatService svc;
    @Test void heartbeat_increments() {
        double before = svc.count();
        svc.beat();
        assertEquals(before + 1, svc.count(), 0.01);
    }
}

