import io.micrometer.core.instrument.*;
import org.springframework.stereotype.*;
import java.util.concurrent.atomic.AtomicLong;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.beans.factory.annotation.Autowired;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;

@Service
class SLOTrackingService {
    private final AtomicLong successes = new AtomicLong(0);
    private final AtomicLong failures  = new AtomicLong(0);
    static final double SLO_TARGET   = 0.999;
    static final double BUDGET       = 1.0 - SLO_TARGET;
    static final double MONTH_MINS   = 43200.0;

    SLOTrackingService(MeterRegistry reg) {
        Gauge.builder("slo.error.budget.remaining.percent", this,
            s -> s.budgetRemaining()).register(reg);
        Gauge.builder("slo.error.budget.consumed.minutes", this,
            s -> s.budgetConsumedMinutes()).register(reg);
    }

    void record(boolean success) {
        if (success) successes.incrementAndGet();
        else         failures.incrementAndGet();
    }

    double errorRate() {
        long total = successes.get() + failures.get();
        return total == 0 ? 0.0 : (double) failures.get() / total;
    }

    double budgetRemaining() {
        double burned = errorRate() / BUDGET;
        return Math.max(0, (1 - burned) * 100);
    }

    double budgetConsumedMinutes() {
        return (errorRate() / BUDGET) * MONTH_MINS;
    }

    boolean isBudgetHealthy() { return budgetRemaining() > 20.0; }
    void reset() { successes.set(0); failures.set(0); }
}

@SpringBootTest
class SLOTrackingTest {
    @Autowired SLOTrackingService svc;
    @BeforeEach void reset() { svc.reset(); }

    @Test void fullBudget_whenNoErrors() {
        for(int i=0;i<1000;i++) svc.record(true);
        assertEquals(100.0, svc.budgetRemaining(), 0.01);
        assertTrue(svc.isBudgetHealthy());
    }

    @Test void budgetExhausted_whenHighErrorRate() {
        for(int i=0;i<999;i++) svc.record(true);
        for(int i=0;i<1;i++)   svc.record(false);
        // 0.1% errors = exactly error budget consumed
        assertTrue(svc.budgetRemaining() < 5.0);
        assertFalse(svc.isBudgetHealthy());
    }

    @Test void partialConsumption_stillHealthy() {
        for(int i=0;i<9999;i++) svc.record(true);
        for(int i=0;i<1;i++)    svc.record(false);
        // 0.01% errors = 10% of budget consumed
        assertTrue(svc.budgetRemaining() > 50.0);
        assertTrue(svc.isBudgetHealthy());
    }
}

