import io.micrometer.core.instrument.*;
import org.springframework.stereotype.*;
import java.util.concurrent.atomic.AtomicLong;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.beans.factory.annotation.Autowired;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;

@Service
class ZerodhaOrderSLO {
    private final AtomicLong ok=new AtomicLong(0),fail=new AtomicLong(0);
    static final double SLO=0.9995; // 99.95%
    static final double BUDGET=1-SLO; // 0.0005

    ZerodhaOrderSLO(MeterRegistry reg){
        Gauge.builder("zerodha.slo.sli",this,s->s.sli()).register(reg);
        Gauge.builder("zerodha.slo.budget.remaining",this,s->s.budgetRemaining()).register(reg);
    }

    void record(boolean success){ if(success)ok.incrementAndGet(); else fail.incrementAndGet(); }
    double sli(){ long t=ok.get()+fail.get(); return t==0?1.0:(double)ok.get()/t; }
    double budgetRemaining(){ return Math.max(0,(1-(1-sli())/BUDGET)*100); }
    boolean shouldFreeze(){ return budgetRemaining()<20.0; }
    void reset(){ ok.set(0); fail.set(0); }
}

// prometheus/rules.yml (as comment):
// - alert: ZerodhaOrderFastBurn
//   expr: |
//     sum(rate(orders_total{status='failure'}[1h]))
//     / sum(rate(orders_total[1h])) > 14.4 * 0.0005
//     AND
//     sum(rate(orders_total{status='failure'}[5m]))
//     / sum(rate(orders_total[5m])) > 14.4 * 0.0005
//   for: 2m
//   labels: { severity: critical }

@SpringBootTest
class ZerodhaOrderSLOTest{
    @Autowired ZerodhaOrderSLO slo;
    @BeforeEach void r(){slo.reset();}
    @Test void sli_whenAllSucceed(){
        for(int i=0;i<1000;i++)slo.record(true);
        assertEquals(1.0,slo.sli(),0.001);
    }
    @Test void budgetRemaining_withLowErrors(){
        for(int i=0;i<9999;i++)slo.record(true);
        slo.record(false);
        // 0.01% error rate = 2% of 0.05% budget consumed → 98% remaining
        assertTrue(slo.budgetRemaining()>80.0);
    }
    @Test void freeze_whenBudgetExhausted(){
        for(int i=0;i<9995;i++)slo.record(true);
        for(int i=0;i<5;i++)slo.record(false);
        // 0.05% error rate = exactly the budget consumed
        assertTrue(slo.shouldFreeze());
    }
}

// 1. ANTI-PATTERN: Alert on every exception (no for: duration)
// Bad:
//   expr: increase(error_log_count[1m]) > 0
//   # Fires on EVERY single exception — even expected ones
// Fix:
//   expr: rate(error_log_count[5m]) > 0.1  # more than 0.1 errors/second
//   for: 5m  # sustained for 5 minutes — not a single fluke error
//
// 2. ANTI-PATTERN: CPU alert (cause, not symptom)
// Bad:
//   expr: cpu_usage_percent > 50
//   # Fires constantly (JIT compilation, GC, traffic bursts)
//   # 50% CPU might mean perfectly healthy traffic
// Fix: REMOVE. Alert on error rate or p99 instead. CPU is a cause, not a symptom.
//   If must keep: cpu_usage_percent > 95 for 10m (near saturation, imminent symptoms)
//
// 3. ANTI-PATTERN: No runbook_url
// Bad: alert with no annotations or no runbook_url
//   # On-call engineer pages at 3am, no idea what to do
// Fix: EVERY alert must have:
//   annotations:
//     runbook_url: 'https://wiki.company.com/runbooks/alert-name'
//     summary: '1-line description of the problem'
//     description: 'Current value: {{ $value }}'
//
// 4. ANTI-PATTERN: Warning alerts at 2am
// Bad: warnings sent to PagerDuty 24/7
//   # On-call burnout: woken up for non-critical issues
// Fix: Use time_of_day in alert routing
//   alertmanager inhibit_rules: silence warnings between 10pm-8am IST
//   OR route warnings to Slack only (check during business hours)
//   ONLY critical alerts should page on-call at night
//
// 5. ANTI-PATTERN: Threshold of > 0 (any single event fires)
// Bad:
//   expr: rate(payments_total{status='failure'}[5m]) > 0
//   # First failed payment (even expected, like card declined) fires alert
// Fix:
//   expr: sum(rate(payments_total{status='failure'}[5m])) /
//         sum(rate(payments_total[5m])) * 100 > 1
//   for: 5m
//   # Error RATE > 1% sustained. Single errors are expected (user error).

public class AlertAntiPatterns { public static void main(String[] a) {
    System.out.println("5 anti-patterns fixed: duration, symptoms, runbooks, timing, thresholds"); } }

import io.micrometer.core.instrument.*;
import io.micrometer.tracing.Tracer;
import io.micrometer.tracing.Span;
import org.slf4j.*;
import org.springframework.stereotype.*;
import org.springframework.scheduling.annotation.Scheduled;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.beans.factory.annotation.Autowired;
import ch.qos.logback.classic.spi.ILoggingEvent;
import ch.qos.logback.core.read.ListAppender;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;
import java.util.concurrent.atomic.AtomicLong;

@Service
class M20FullObservability {
    private static final Logger log = LoggerFactory.getLogger(M20FullObservability.class);
    private final MeterRegistry reg;
    private final Tracer tracer;
    private final Timer timer;
    private final Counter heartbeat;
    private final AtomicLong ok=new AtomicLong(0),fail=new AtomicLong(0);
    static final double SLO=0.999, BUDGET=1-SLO;

    M20FullObservability(MeterRegistry r, Tracer t) {
        reg=r; tracer=t;
        timer=Timer.builder("m20.payment.duration").publishPercentiles(0.5,0.95,0.99).register(reg);
        heartbeat=Counter.builder("m20.heartbeat").register(reg);
        Gauge.builder("m20.slo.budget.remaining",this,s->s.budgetRemaining()).register(reg);
    }

    String processPayment(String gw, double amount, boolean succeed) {
        return timer.record(()->{
            Span s=tracer.nextSpan().name("m20.payment");
            try(var ws=tracer.withSpan(s.start())){
                s.tag("gateway",gw);
                org.slf4j.MDC.put("gateway",gw);
                log.info("payment.start gateway={} amount={}",gw,amount);
                if(succeed){
                    ok.incrementAndGet();
                    reg.counter("m20.payments","status","success").increment();
                    log.info("payment.success gateway={}",gw);
                    return "PAY-OK";
                }else{
                    fail.incrementAndGet();
                    reg.counter("m20.payments","status","failure").increment();
                    log.error("payment.failure gateway={}",gw);
                    return "PAY-FAIL";
                }
            }finally{s.end();org.slf4j.MDC.remove("gateway");}
        });
    }

    @Scheduled(fixedRate=30_000) public void beat(){heartbeat.increment();}

    double budgetRemaining(){
        long t=ok.get()+fail.get();
        if(t==0)return 100.0;
        double errRate=(double)fail.get()/t;
        return Math.max(0,(1-errRate/BUDGET)*100);
    }
}

@SpringBootTest
class M20FinalSynthesisTest{
    @Autowired M20FullObservability svc;
    @Autowired MeterRegistry reg;
    @Autowired Tracer tracer;
    ch.qos.logback.classic.Logger l=(ch.qos.logback.classic.Logger)LoggerFactory.getLogger(M20FullObservability.class);
    ListAppender<ILoggingEvent> appender=new ListAppender<>();
    @BeforeEach void s(){appender.start();l.addAppender(appender);}
    @AfterEach  void c(){l.detachAppender(appender);appender.stop();appender.list.clear();}
    @Test void metrics_and_slo(){
        svc.processPayment("visa",999.0,true);
        assertNotNull(reg.find("m20.payments").tag("status","success").counter());
        assertEquals(100.0,svc.budgetRemaining(),0.01);
    }
    @Test void tracing_and_logs(){
        svc.processPayment("mc",499.0,false);
        assertFalse(appender.list.isEmpty());
        assertTrue(appender.list.stream().anyMatch(e->e.getFormattedMessage().contains("payment.start")));
    }
    @Test void heartbeat_and_tracer(){
        assertNotNull(tracer);
        svc.beat();
        assertTrue(reg.find("m20.heartbeat").counter().count()>=1);
    }
}
